import React, { Fragment } from "react";
import "./parcours.css";

function parcours() {
  return (
    <Fragment>
      <section id="parcours" className="page-section">
        <h2 className="text-uppercase text-center">Mon parcours</h2>
        <br />
      </section>
    </Fragment>
  );
}

export default parcours;
